// // This comment suggests that the circuit is designed to produce a low output when an odd number of inputs are high.
module xnor_gate_4input (
    input wire A,
    input wire B,
    input wire C,
    input wire D,
    output wire Y
);

assign Y = ~(A ^ B ^ C ^ D); // XNOR operation for 4 inputs

endmodule
